import { products } from "../data.js";
import type { Product } from "../types.js";
import { AppError } from "../errors.js";

interface ProductFilters {
  category?: string;
  minPrice?: string;
  maxPrice?: string;
}

interface ProductListResult {
  products: Product[];
  summary: {
    count: number;
    totalInventoryValue: number;
    averagePrice: number;
  };
}

interface ProductDetail extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export function listProducts(filters: ProductFilters): ProductListResult {
  let filtered = [...products];

  if (filters.category) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice) {
    const min = parseFloat(filters.minPrice);
    if (!isNaN(min)) {
      filtered = filtered.filter((p) => p.price >= min);
    }
  }

  if (filters.maxPrice) {
    const max = parseFloat(filters.maxPrice);
    if (!isNaN(max)) {
      filtered = filtered.filter((p) => p.price <= max);
    }
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}

export function getProductById(id: number): ProductDetail {
  const product = products.find((p) => p.id === id);

  if (!product) {
    throw new AppError(404, "Product not found");
  }

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

export function adjustProductStock(
  id: number,
  adjustment: unknown
): ProductDetail {
  const product = products.find((p) => p.id === id);

  if (!product) {
    throw new AppError(404, "Product not found");
  }

  if (typeof adjustment !== "number") {
    throw new AppError(400, "adjustment must be a number");
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    throw new AppError(400, "Insufficient stock");
  }

  product.stock = newStock;

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}

