import { orders, products, getNextOrderId } from "../data.js";
import type { CreateOrderInput, Order, OrderItem } from "../types.js";
import { AppError } from "../errors.js";

interface OrderFilters {
  userId?: string;
  status?: string;
}

interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

type EnrichedOrderItem = OrderItem & { productName: string };
type EnrichedOrder = Omit<Order, "items"> & { items: EnrichedOrderItem[] };

export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId) {
    const uid = parseInt(filters.userId, 10);
    if (!isNaN(uid)) {
      filtered = filtered.filter((o) => o.userId === uid);
    }
  }

  if (filters.status) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(id: number): EnrichedOrder {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    throw new AppError(404, "Order not found");
  }

  const enrichedItems: EnrichedOrderItem[] = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(input: CreateOrderInput): Order {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new AppError(400, "userId and items are required");
  }

  if (input.items.length === 0) {
    throw new AppError(400, "Order must have at least one item");
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new AppError(400, `Product ${item.productId} not found`);
    }

    if (item.quantity <= 0) {
      throw new AppError(400, "Quantity must be positive");
    }

    if (product.stock < item.quantity) {
      throw new AppError(400, `Insufficient stock for ${product.name}`);
    }

    // Deduct stock
    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return order;
}

export function updateOrderStatus(id: number, status: string): Order {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    throw new AppError(404, "Order not found");
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(status)) {
    throw new AppError(
      400,
      `Invalid status. Must be one of: ${validStatuses.join(", ")}`
    );
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    throw new AppError(
      400,
      `Cannot transition from ${order.status} to ${status}`
    );
  }

  order.status = status as Order["status"];

  return order;
}

